// Script: generar_36_fix_menu_editar_eliminar.js
// Que hace: corrige el bug donde el menu de Editar/Eliminar (en Vacunas
// y Antiparasitarios) se cortaba por el borde de la pantalla y bloqueaba
// el scroll cuando se abria en una tarjeta cerca del final.
//
// Antes: el menu era una burbuja flotante que aparecia justo debajo del
// boton \u22ee, lo que la hacia salirse de la pantalla en tarjetas al final
// de la lista, y la capa invisible para cerrarlo bloqueaba el scroll.
//
// Ahora: tocar \u22ee abre un modal fijo desde abajo (igual estilo que los
// formularios de crear/editar), siempre centrado y visible completo sin
// importar donde este la tarjeta en la pantalla.
//
// Como correrlo: node generar_36_fix_menu_editar_eliminar.js
// Confirma "OK: app/prevencion/page.tsx"

const fs = require('fs');
const path = require('path');

const filePath = path.join('app', 'prevencion', 'page.tsx');
const b64 = "";
const content = Buffer.from(b64, 'base64').toString('utf8');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

fs.writeFileSync(filePath, content, 'utf8');
console.log('OK: ' + filePath);
